+fn is_shell_env_assignment(token: &str) -> bool {
+    let Some((name, _value)) = token.split_once('=') else {
+        return false;
+    };
+
+    !name.is_empty()
+        && name
+            .bytes()
+            .enumerate()
+            .all(|(idx, byte)| match byte {
+                b'a'..=b'z' | b'A'..=b'Z' | b'_' => true,
+                b'0'..=b'9' => idx > 0,
+                _ => false,
+            })
+}
